#include <iostream>
using namespace std;
int n,sum=2,a[40][40];
int main(){
	cin>>n;
	a[1][n/2+1]=1;
	int x=1,y=n/2+1;
	while(sum<=n*n){
		x-=1;
		if(x==0)x=n;
		y+=1;
		if(y>n)y=1;
		if(a[x][y]==0)a[x][y]=sum++;
		else{
			x+=2;
			if(x>n)x-=n;
			y-=1;
			if(y==0)y=n;
			a[x][y]=sum++;
		}
	}
	for(int i=1;i<=n;i++){
		for(int j=1;j<=n;j++){
			cout<<a[i][j]<<' ';
		}
		cout<<endl;
	}
	return 0;
}
